namespace llvm {
namespace Xtensa {
enum PartialMappingIdx {
  PMI_GPR,
  PMI_Min = PMI_GPR,
};

RegisterBankInfo::PartialMapping PartMappings[]{
    {0, 32, GPRRegBank}

};

enum ValueMappingIdx {
    InvalidIdx = 0,
    GPRIdx = 1,
};

RegisterBankInfo::ValueMapping ValueMappings[] = {
    // invalid
    {nullptr, 0},
    // up to 3 operands in GPRs
    {&PartMappings[PMI_GPR - PMI_Min], 1},
    {&PartMappings[PMI_GPR - PMI_Min], 1},
    {&PartMappings[PMI_GPR - PMI_Min], 1}

};

} // end namespace Xtensa
} // end namespace llvm

using namespace llvm;

XtensaRegisterBankInfo::XtensaRegisterBankInfo(const TargetRegisterInfo &TRI)
    : XtensaGenRegisterBankInfo() {}

const RegisterBank &
XtensaRegisterBankInfo::getRegBankFromRegClass(const TargetRegisterClass &RC,
                                             LLT) const {
  using namespace Xtensa;

  switch (RC.getID()) {
  case Xtensa::ARRegClassID:
    return getRegBank(Xtensa::GPRRegBankID);
  default:
    llvm_unreachable("Register class not supported");
  }
}


